class Solution:
    def is_power_of_two(self, n: int) -> bool:
        if n <= 0:
            return False
        return (n & (n - 1)) == 0

def main():
    s = Solution()
    n = int(input())
    print('Yes' if s.is_power_of_two(n) else 'No')
if __name__ == '__main__':
    main()

