class Solution {
    public:
        bool isPowerOfTwo(int n)
        {
            if(n <= 0) return false;
            return (n & (n - 1)) == 0;
        }
};

int main(){
    Solution solution;
    int n;
    std::cin >> n;
    std::cout << (solution.isPowerOfTwo(n) ? "Yes" : "No");
    return 0;
}
